+fn trace_swarm_post_commit_visibility(
+    conn: &Connection,
+    config: &RunConfig,
+    worker_id: usize,
+    id: i64,
+    seq: i64,
+    payload: &str,
+) {
+    if !group_commit_trace_enabled() {
